module register_8bit (
    input reset,
    input load,
    input clear,
    input [7:0] data_in,
    output reg [7:0] data_out
);

    always @(posedge reset) begin
        if (clear)
            data_out <= 8'b00000000;
        else if (load)
            data_out <= data_in;
    end

endmodule
